// 准备调用Dify的数据
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // 构造Dify API所需的输入格式
  const difyInput = {
    inputs: {
      user_query: data.query || '请分析这些数据',
      data_content: JSON.stringify(data.data || data, null, 2)
    },
    response_mode: 'blocking',
    user: data.user_id || 'n8n-workflow'
  };

  results.push({
    json: {
      ...data,
      _dify_input: difyInput,
      _original_data: data
    }
  });
}

return results;

// 解析Dify返回结果
const items = $input.all();
const results = [];

for (const item of items) {
  const difyResponse = item.json;

  // 提取Dify的分析结果
  const analysis = {
    answer: difyResponse.answer || '',
    conversation_id: difyResponse.conversation_id || '',
    message_id: difyResponse.message_id || '',
    created_at: difyResponse.created_at || new Date().toISOString(),
    metadata: difyResponse.metadata || {}
  };

  // 尝试解析JSON格式的回答（如果Dify返回结构化数据）
  let parsedAnswer = null;
  try {
    parsedAnswer = JSON.parse(analysis.answer);
  } catch (e) {
    // 如果不是JSON，保持原始文本
    parsedAnswer = analysis.answer;
  }

  results.push({
    json: {
      original_data: item.json._original_data,
      dify_analysis: analysis,
      parsed_result: parsedAnswer,
      processing_time: Date.now() - new Date(item.json._original_data.timestamp || Date.now()).getTime(),
      status: 'completed'
    }
  });
}

return results;

// 质量评分
const items = $input.all();
const results = [];

for (const item of items) {
  const analysis = item.json.dify_analysis;
  const parsedResult = item.json.parsed_result;

  // 计算质量分数
  let qualityScore = 0.5; // 基础分

  // 1. 回答完整性（30%）
  const completeness = analysis.answer && analysis.answer.length > 50 ? 1.0 : 0.5;
  qualityScore += completeness * 0.3;

  // 2. 结构化程度（30%）
  const isStructured = typeof parsedResult === 'object' && parsedResult !== null;
  qualityScore += (isStructured ? 1.0 : 0.3) * 0.3;

  // 3. 响应速度（20%）
  const responseTime = item.json.processing_time || 0;
  const speedScore = responseTime < 5000 ? 1.0 : (responseTime < 10000 ? 0.7 : 0.3);
  qualityScore += speedScore * 0.2;

  // 4. 元数据完整性（20%）
  const hasMetadata = analysis.metadata && Object.keys(analysis.metadata).length > 0;
  qualityScore += (hasMetadata ? 1.0 : 0.5) * 0.2;

  results.push({
    json: {
      ...item.json,
      quality_score: qualityScore,
      need_review: qualityScore < 0.7,
      quality_breakdown: {
        completeness,
        structured: isStructured ? 1.0 : 0.3,
        speed: speedScore,
        metadata: hasMetadata ? 1.0 : 0.5
      }
    }
  });
}

return results;

// 保存高质量结果
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      success: true,
      message: '分析结果已保存',
      data: item.json,
      saved_at: new Date().toISOString()
    }
  });

  console.log('✅ 高质量分析结果已保存');
}

return results;

// 推送人工复核
const items = $input.all();
const results = [];

for (const item of items) {
  const reviewTask = {
    task_id: `review-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    created_at: new Date().toISOString(),
    data: item.json,
    quality_score: item.json.quality_score,
    review_reason: '质量评分低于阈值',
    status: 'pending'
  };

  results.push({
    json: {
      success: true,
      message: '已推送人工复核队列',
      review_task: reviewTask,
      queued_at: new Date().toISOString()
    }
  });

  console.log('⚠️  低质量结果已推送复核队列');
}

return results;
